from typing import Optional
import logging

logger = logging.getLogger(__name__)

class ConsentGate:
    def __init__(self, consent_store, audit_logger):
        self.store = consent_store
        self.audit = audit_logger

    def check(
        self,
        user_id: str,
        feature_id: str,
        required_purposes: list[str],
        required_data_categories: list[str],
    ) -> tuple[bool, str]:
        """Returns (allowed, reason). Logs every access."""
        record: Optional[ConsentRecord] = self.store.get(
            user_id=user_id, feature_id=feature_id
        )

        if record is None:
            self.audit.record(user_id, feature_id, "no_record", allowed=False)
            return False, "no_consent_record"

        if not record.is_active():
            self.audit.record(user_id, feature_id, "inactive", allowed=False)
            return False, "consent_inactive"

        for purpose in required_purposes:
            if not record.allows_purpose(purpose):
                self.audit.record(user_id, feature_id, f"missing_purpose:{purpose}", allowed=False)
                return False, f"missing_purpose:{purpose}"

        for category in required_data_categories:
            if not record.allows_data_category(category):
                self.audit.record(user_id, feature_id, f"excluded_category:{category}", allowed=False)
                return False, f"excluded_category:{category}"

        self.audit.record(user_id, feature_id, "granted", allowed=True)
        return True, "granted"


# Usage in an AI feature handler
def run_ai_assistant(user_id: str, query: str, context_data: dict, gate: ConsentGate):
    allowed, reason = gate.check(
        user_id=user_id,
        feature_id="ai_assistant",
        required_purposes=["personalization"],
        required_data_categories=list(context_data.keys()),
    )
    if not allowed:
        # Return a degraded response or prompt for consent
        return {"status": "consent_required", "reason": reason}
    return invoke_model(query, context_data)
